/**
 * Health Dashboard API - Aggregated system health and metrics
 * 
 * GET /api/system/health-dashboard
 * Returns comprehensive health data for the admin dashboard:
 * - Service health checks (DB, Redis, Storage, FFmpeg, APIs)
 * - System resources (CPU, memory, uptime)
 * - Queue status (pending, processing, completed jobs)
 * - API metrics (request count, error rate)
 * - Timestamps for auto-refresh
 */

import { NextRequest, NextResponse } from 'next/server';
import { logger } from '@lib/logger';
import { applyRateLimit } from '@/lib/rate-limit';
import { healthCheckService, type ServiceHealth } from '@lib/monitoring/health-check';
import { metricsCollector } from '@lib/monitoring/metrics';
import os from 'os';

// -------------------------------------------------------
// Types
// -------------------------------------------------------

interface QueueStats {
  pending: number;
  processing: number;
  completed: number;
  failed: number;
  total: number;
}

interface SystemResources {
  cpu: {
    load: number;
    cores: number;
    loadPercentage: number;
  };
  memory: {
    totalMB: number;
    usedMB: number;
    freeMB: number;
    usagePercentage: number;
  };
  process: {
    heapUsedMB: number;
    heapTotalMB: number;
    rssMB: number;
    uptimeSeconds: number;
  };
}

interface ApiMetrics {
  totalRequests: number;
  requestsLastMinute: number;
  metricsCount: number;
}

interface HealthDashboardResponse {
  overall: 'healthy' | 'degraded' | 'unhealthy';
  services: ServiceHealth[];
  resources: SystemResources;
  queue: QueueStats;
  api: ApiMetrics;
  environment: string;
  nodeVersion: string;
  appVersion: string;
  timestamp: string;
  uptimeFormatted: string;
}

// -------------------------------------------------------
// Helpers
// -------------------------------------------------------

function formatUptime(seconds: number): string {
  const days = Math.floor(seconds / 86400);
  const hours = Math.floor((seconds % 86400) / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);

  const parts: string[] = [];
  if (days > 0) parts.push(`${days}d`);
  if (hours > 0) parts.push(`${hours}h`);
  if (mins > 0) parts.push(`${mins}m`);
  parts.push(`${secs}s`);
  return parts.join(' ');
}

async function getQueueStats(): Promise<QueueStats> {
  try {
    const { prisma } = await import('@lib/prisma');
    const [pending, processing, completed, failed] = await Promise.all([
      prisma.render_jobs.count({ where: { status: { in: ['pending', 'queued'] } } }),
      prisma.render_jobs.count({ where: { status: 'processing' } }),
      prisma.render_jobs.count({ where: { status: 'completed' } }),
      prisma.render_jobs.count({ where: { status: 'failed' } }),
    ]);
    return {
      pending,
      processing,
      completed,
      failed,
      total: pending + processing + completed + failed,
    };
  } catch {
    // Table might not exist yet
    return { pending: 0, processing: 0, completed: 0, failed: 0, total: 0 };
  }
}

function getSystemResources(): SystemResources {
  const cpuCount = os.cpus().length || 1;
  const loadAvg = os.loadavg()[0] || 0;
  const totalMem = os.totalmem();
  const freeMem = os.freemem();
  const usedMem = totalMem - freeMem;
  const mem = process.memoryUsage();

  return {
    cpu: {
      load: Number(loadAvg.toFixed(2)),
      cores: cpuCount,
      loadPercentage: Math.min(Math.round((loadAvg / cpuCount) * 100), 100),
    },
    memory: {
      totalMB: Math.round(totalMem / 1048576),
      usedMB: Math.round(usedMem / 1048576),
      freeMB: Math.round(freeMem / 1048576),
      usagePercentage: Math.round((usedMem / totalMem) * 100),
    },
    process: {
      heapUsedMB: Math.round(mem.heapUsed / 1048576),
      heapTotalMB: Math.round(mem.heapTotal / 1048576),
      rssMB: Math.round(mem.rss / 1048576),
      uptimeSeconds: Math.round(process.uptime()),
    },
  };
}

function getApiMetrics(): ApiMetrics {
  const systemMetrics = metricsCollector.getSystemMetrics();
  return {
    totalRequests: systemMetrics.requests.total,
    requestsLastMinute: systemMetrics.requests.lastMinute,
    metricsCount: metricsCollector.getMetrics().length,
  };
}

// -------------------------------------------------------
// Route Handler
// -------------------------------------------------------

export async function GET(request: NextRequest) {
  try {
    const rateLimitBlocked = await applyRateLimit(request, 'health-dashboard-get', 30);
    if (rateLimitBlocked) return rateLimitBlocked;

    // Run all checks in parallel
    const [healthResult, queueStats] = await Promise.all([
      healthCheckService.checkAll(),
      getQueueStats(),
    ]);

    const resources = getSystemResources();
    const apiMetrics = getApiMetrics();

    const response: HealthDashboardResponse = {
      overall: healthResult.overall,
      services: healthResult.services,
      resources,
      queue: queueStats,
      api: apiMetrics,
      environment: process.env.NODE_ENV || 'development',
      nodeVersion: process.version,
      appVersion: process.env.npm_package_version || '1.0.0',
      timestamp: new Date().toISOString(),
      uptimeFormatted: formatUptime(resources.process.uptimeSeconds),
    };

    const statusCode = healthResult.overall === 'healthy' ? 200
      : healthResult.overall === 'degraded' ? 200
      : 503;

    return NextResponse.json(response, {
      status: statusCode,
      headers: {
        'Cache-Control': 'no-store, no-cache, must-revalidate',
        'X-Health-Status': healthResult.overall,
      },
    });
  } catch (error: unknown) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error('Health dashboard endpoint error', err, {
      component: 'API: system/health-dashboard',
    });
    return NextResponse.json(
      {
        overall: 'unhealthy',
        error: 'Failed to gather health data',
        message: err.message,
        timestamp: new Date().toISOString(),
      },
      { status: 500 },
    );
  }
}
